45	+static float cal_piou2(vector<float> box, vector<float> truth, float Lambda = 1.2) {
46	+  // Calculate standard IoU first
47	+  float w = overlap(box[0], box[2], truth[0], truth[2]);
48	+  float h = overlap(box[1], box[3], truth[1], truth[3]);
49	+  if (w < 0 || h < 0) return 0;
50	+
51	+  float inter_area = w * h;
52	+  float union_area = box[2] * box[3] + truth[2] * truth[3] - inter_area;
53	+  float iou = inter_area / union_area;
54	+  
55	+  // Calculate PIoU2 components
56	+  // First, get box coordinates in x1,y1,x2,y2 format
57	+  float b1_x1 = box[0] - box[2]/2.0;
58	+  float b1_y1 = box[1] - box[3]/2.0;
59	+  float b1_x2 = box[0] + box[2]/2.0;
60	+  float b1_y2 = box[1] + box[3]/2.0;
61	+  
62	+  float b2_x1 = truth[0] - truth[2]/2.0;
63	+  float b2_y1 = truth[1] - truth[3]/2.0;
64	+  float b2_x2 = truth[0] + truth[2]/2.0;
65	+  float b2_y2 = truth[1] + truth[3]/2.0;
66	+  
67	+  // Calculate diagonal distances
68	+  float dw1 = fabs(min(b1_x2, b1_x1) - min(b2_x2, b2_x1));
69	+  float dw2 = fabs(max(b1_x2, b1_x1) - max(b2_x2, b2_x1));
70	+  float dh1 = fabs(min(b1_y2, b1_y1) - min(b2_y2, b2_y1));
71	+  float dh2 = fabs(max(b1_y2, b1_y1) - max(b2_y2, b2_y1));
72	+  
73	+  // Calculate the normalized center distance
74	+  float P = ((dw1 + dw2) / fabs(truth[2]) + (dh1 + dh2) / fabs(truth[3])) / 4.0;
75	+  
76	+  // Calculate L_v1 term
77	+  float L_v1 = 1.0 - iou - exp(-(P*P)) + 1.0;
78	+  
79	+  // Calculate PIoU2
80	+  float q = exp(-P);
81	+  float x = q * Lambda;
82	+  return 1.0 - (3.0 * x * exp(-(x*x)) * L_v1);
83	+}
