+static float cal_piou2(vector<float> box, vector<float> truth, float Lambda = 1.2) {
+  // Calculate standard IoU first
+  float w = overlap(box[0], box[2], truth[0], truth[2]);
+  float h = overlap(box[1], box[3], truth[1], truth[3]);
+  if (w < 0 || h < 0) return 0;
+
+  float inter_area = w * h;
+  float union_area = box[2] * box[3] + truth[2] * truth[3] - inter_area;
+  float iou = inter_area / union_area;
+  
+  // Calculate PIoU2 components
+  // First, get box coordinates in x1,y1,x2,y2 format
+  float b1_x1 = box[0] - box[2]/2.0;
+  float b1_y1 = box[1] - box[3]/2.0;
+  float b1_x2 = box[0] + box[2]/2.0;
+  float b1_y2 = box[1] + box[3]/2.0;
+  
+  float b2_x1 = truth[0] - truth[2]/2.0;
+  float b2_y1 = truth[1] - truth[3]/2.0;
+  float b2_x2 = truth[0] + truth[2]/2.0;
+  float b2_y2 = truth[1] + truth[3]/2.0;
+  
+  // Calculate diagonal distances
+  float dw1 = fabs(min(b1_x2, b1_x1) - min(b2_x2, b2_x1));
+  float dw2 = fabs(max(b1_x2, b1_x1) - max(b2_x2, b2_x1));
+  float dh1 = fabs(min(b1_y2, b1_y1) - min(b2_y2, b2_y1));
+  float dh2 = fabs(max(b1_y2, b1_y1) - max(b2_y2, b2_y1));
+  
+  // Calculate the normalized center distance
+  float P = ((dw1 + dw2) / fabs(truth[2]) + (dh1 + dh2) / fabs(truth[3])) / 4.0;
+  
+  // Calculate L_v1 term
+  float L_v1 = 1.0 - iou - exp(-(P*P)) + 1.0;
+  
+  // Calculate PIoU2
+  float q = exp(-P);
+  float x = q * Lambda;
+  return 1.0 - (3.0 * x * exp(-(x*x)) * L_v1);
+}
